#include <stdio.h>
#include <stdlib.h>

typedef struct {int w; int s;} Person;

int cmp(const void *a, const void *b) {
    const Person *p1 = (const Person *)a;
    const Person *p2 = (const Person *)b;
    long long left = (long long)p1->s * p2->w;
    long long right = (long long)p2->s * p1->w;
    if (left > right) return -1; // descending s/w
    if (left < right) return 1;
    return 0;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        Person *a = (Person*)malloc(n * sizeof(Person));
        for (int i=0;i<n;i++) scanf("%d %d", &a[i].w, &a[i].s);
        qsort(a, n, sizeof(Person), cmp);
        double minSpeed = 1e100;
        for (int i=0;i<n/2;i++) {
            int w1 = a[i].w, s1 = a[i].s;
            int w2 = a[n-1-i].w, s2 = a[n-1-i].s;
            double speed = (s1 + s2) / (20.0 + w1 + w2);
            if (speed < minSpeed) minSpeed = speed;
        }
        printf("%.6f\n", minSpeed);
        free(a);
    }
    return 0;
}

