import java.io.*;
import java.util.*;
public class Main {
    static class Person {
        int w, s;
        Person(int w, int s){this.w=w;this.s=s;}
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            int n = Integer.parseInt(br.readLine().trim());
            Person[] arr = new Person[n];
            for (int i = 0; i < n; i++) {
                st = new StringTokenizer(br.readLine());
                int w = Integer.parseInt(st.nextToken());
                int s = Integer.parseInt(st.nextToken());
                arr[i] = new Person(w, s);
            }
            Arrays.sort(arr, (p1, p2) -> Long.compare((long)p2.s * p1.w, (long)p1.s * p2.w)); // descending s/w
            double minSpeed = Double.MAX_VALUE;
            for (int i = 0; i < n/2; i++) {
                double speed = (arr[i].s + arr[n-1-i].s) / (20.0 + arr[i].w + arr[n-1-i].w);
                if (speed < minSpeed) minSpeed = speed;
            }
            out.append(String.format(Locale.US, "%.6f\n", minSpeed));
        }
        System.out.print(out.toString());
    }
}

