const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (data.length === 0) process.exit(0);
const T = Number(data[idx++]);
let outputs = [];
for (let tc = 0; tc < T; tc++) {
  const n = Number(data[idx++]);
  let people = new Array(n);
  for (let i = 0; i < n; i++) {
    const w = Number(data[idx++]);
    const s = Number(data[idx++]);
    people[i] = [w, s];
  }
  // sort by descending s/w using cross multiplication to avoid floating errors
  people.sort((a, b) => b[1] * a[0] - a[1] * b[0]);
  let minSpeed = Infinity;
  for (let i = 0; i < n / 2; i++) {
    const w1 = people[i][0], s1 = people[i][1];
    const w2 = people[n - 1 - i][0], s2 = people[n - 1 - i][1];
    const speed = (s1 + s2) / (20 + w1 + w2);
    if (speed < minSpeed) minSpeed = speed;
  }
  outputs.push(minSpeed.toFixed(6));
}
console.log(outputs.join('\n'));

